129→        void shouldCreateTaskWith201() throws Exception {
130→            String body = createTaskJson("My New Task", "Task description", "HIGH");
131→
132→            MvcResult result = mockMvc.perform(post("/api/tasks")
133→                            .header("Authorization", "Bearer " + authToken)
